using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Round-trip using the typed info
var json = JsonSerializer.Serialize(new Person("Ada", 37), personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");

// 2) Probe without throwing: TryGetTypeInfo returns false when metadata is unavailable
//    Use an empty resolver so nothing is resolvable.
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => throw new InvalidOperationException("blocked") }
    }
};

bool found = restrictedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probeResult);
Console.WriteLine($"\nTryGetTypeInfo on restricted resolver => found: {found}, result: {probeResult?.Type.Name ?? "(null)"}");

// Confirm it works positively too
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? probeResult2);
Console.WriteLine($"TryGetTypeInfo on normal resolver    => found: {found2}, result: {probeResult2?.Type.Name ?? "(null)"}");

public record Person(string Name, int Age);

